// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Blueprint_Missing_Message (Full Dynamic)
// DESC: Recupero nomi umani dal catalogo e navigazione dinamica
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;

// 1. Recupero basi dati
const catalog = item.service_catalog_setup || {};
const userReq = item.user_request || {};
const owner = item.owner_data || {};

const skuId = userReq.ghost_id;
const categoryId = userReq.category_id;

// 2. Lookup Intelligente nel Catalogo
let skuName = skuId; // Fallback
let categoryName = "Area selezionata"; // Fallback
let macro = "sop"; // Default

if (catalog.categories && Array.isArray(catalog.categories)) {
    // Troviamo la categoria corretta
    const currentCategory = catalog.categories.find(cat => cat.callback_data === categoryId);

    if (currentCategory) {
        // Estraiamo il nome della categoria (pulito)
        categoryName = currentCategory.short_name || currentCategory.name.replace(/\[.*?\]/g, '').trim();
        macro = (currentCategory.macrocategories || "SOP").toLowerCase();

        // Troviamo il nome della procedura specifica dentro le subcategories
        if (currentCategory.subcategories) {
            const currentProcedure = currentCategory.subcategories.find(sub => sub.callback_data === skuId);
            if (currentProcedure) {
                skuName = currentProcedure.short_name || currentProcedure.name;
            }
        }
    }
}

// 3. Costruzione messaggi localizzati
const rawLang = (owner.lenguage || 'it').toLowerCase();
let lang = rawLang.includes('en') ? 'en' : 'it';

const translations = {
  'it': {
    title: "🛠️ <b>CONFIGURAZIONE NECESSARIA</b>",
    msg: `La procedura <b>"${skuName}"</b> (nella categoria <i>${categoryName}</i>) non è ancora stata configurata.`,
    explanation: "Per renderla operativa su Telegram, dobbiamo attivare il suo 'Blueprint'. Potrai poi personalizzare ogni passaggio sulla dashboard SiteBoS.",
    btn_activate: "🚀 Attiva Procedura Ora",
    btn_back: `⬅️ Torna a ${categoryName}`
  },
  'en': {
    title: "🛠️ <b>CONFIGURATION REQUIRED</b>",
    msg: `The procedure <b>"${skuName}"</b> (under <i>${categoryName}</i>) has not been configured yet.`,
    explanation: "To make it operational on Telegram, we need to activate its 'Blueprint'. You can then customize each step on the SiteBoS dashboard.",
    btn_activate: "🚀 Activate Procedure Now",
    btn_back: `⬅️ Back to ${categoryName}`
  }
};

const t = translations[lang];

// 4. Payload per Telegram
const backCallback = `get_active_${macro}_${categoryId}`;
const chatId = item.chat_id || (item.body.callback_query && item.body.callback_query.message.chat.id);
const messageId = item.message_id || (item.body.callback_query && item.body.callback_query.message.message_id);

return [{
  json: {
    telegramApiPayload: {
      method: "editMessageText",
      chat_id: chatId,
      message_id: messageId,
      text: `${t.title}\n━━━━━━━━━━━━━━━━━━━━\n\n${t.msg}\n\n${t.explanation}`,
      parse_mode: "HTML",
      reply_markup: {
        inline_keyboard: [
          [{ text: t.btn_activate, callback_data: `confirm_blueprint_build_${skuId}` }],
          [{ text: t.btn_back, callback_data: backCallback }]
        ]
      }
    }
  }
}];

// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_System_Error_Message
// DESC: Errore tecnico. Permette il retry tramite EDIT del messaggio.
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;
const owner = item.owner_data || {};

// Recupero la base URL dalla variabile dinamica
const baseUrl = item.urlMiniApp; 

const chatId = item.body.chat_id || owner.chat_id;
const messageId = item.body.message_id; 
const sopId = item.body.sop_id;
const stepId = item.body.step_id;
const evType = item.body.evidence_type || "VISION";

// Costruzione URL dinamica: sostituisco la parte fissa con baseUrl
const webAppUrl = `${baseUrl}certificator.html?sop_id=${sopId}&step_id=${stepId}&message_id=${messageId}&evidence_type=${evType}`;

const rawLang = (owner.lenguage || 'it').toLowerCase();
let lang = rawLang.includes('en') ? 'en' : 'it';

const t = {
  it: {
    title: "⚠️ <b>ERRORE DI SISTEMA</b>",
    msg: "Problema tecnico durante l'analisi (Timeout o Errore AI).",
    action: "Nessun credito scalato. Per favore, riprova.",
    btn_retry: "🔄 Riprova Acquisizione",
    btn_back: "⬅️ Torna Indietro"
  },
  en: {
    title: "⚠️ <b>SYSTEM ERROR</b>",
    msg: "Technical issue during analysis (Timeout or AI Error).",
    action: "No credits deducted. Please try again.",
    btn_retry: "🔄 Retry Acquisition",
    btn_back: "⬅️ Go Back"
  }
}[lang];

const telegramApiPayload = {
  method: "editMessageText",
  chat_id: chatId,
  message_id: messageId,
  text: `${t.title}\n━━━━━━━━━━━━━━━━━━━━\n${t.msg}\n\n${t.action}`,
  parse_mode: "HTML",
  reply_markup: {
    inline_keyboard: [
      [{ text: t.btn_retry, web_app: { url: webAppUrl } }],
      [{ text: t.btn_back, callback_data: `get_active_sop_SVC_${sopId.replace('SVC_', '')}` }]
    ]
  }
};

return [{ json: { ...item, telegramApiPayload: telegramApiPayload } }];

// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Evidence_Rejected_Message
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;
const owner = item.owner_data || {};

function clean(text) {
    if (!text || typeof text !== 'string') return "";
    return text.replace(/<(?!b\b|i\b|u\b|s\b|code\b|a\b|pre\b|\/b\b|\/i\b|\/u\b|\/s\b|\/code\b|\/a\b|\/pre\b)[^>]+>/gi, '');
}

const chatId = item.body.chat_id || owner.chat_id;
const messageId = item.body.message_id; 
const sopId = item.body.sop_id;
const stepId = item.body.step_id;
const evType = item.body.evidence_type || "VISION";

const log = item.Evicence_Rational_Log || {};
const stepName = clean(item.current_step_context?.step_name || "OPERAZIONE");
const legalStatus = clean(log.fiscal_legal_status || "");
const strategy = clean(log.strategic_insight || "");
const reason = clean(log.rationale || "L'evidenza fornita non rispetta i criteri di accettazione.");

const rawLang = (owner.lenguage || 'it').toLowerCase();
let lang = rawLang.includes('en') ? 'en' : 'it';

const t = {
  it: {
    title: `🛑 <b>EVIDENZA RESPINTA: ${stepName.toUpperCase()}</b>`,
    section_reason: "🔍 <b>MOTIVO DEL RIFIUTO:</b>",
    section_legal: "⚖️ <b>ANALISI DI COMPLIANCE:</b>",
    section_strategy: "💡 <b>AZIONI CORRETTIVE:</b>",
    btn_retry: "📸 Correggi e Riprova",
    btn_back: "⬅️ Torna alla Procedura"
  },
  en: {
    title: `🛑 <b>EVIDENCE REJECTED: ${stepName.toUpperCase()}</b>`,
    section_reason: "🔍 <b>REASON FOR REJECTION:</b>",
    section_legal: "⚖️ <b>COMPLIANCE ANALYSIS:</b>",
    section_strategy: "💡 <b>CORRECTIVE ACTIONS:</b>",
    btn_retry: "📸 Correct and Retry",
    btn_back: "⬅️ Back to Procedure"
  }
}[lang];

// 4. Costruzione URL Mini App per il Retry (Rimosso user_id, vat e chat_id)
const baseUrl = item.urlMiniApp; 
const webAppUrl = `${baseUrl}certificator.html?sop_id=${sopId}&step_id=${stepId}&message_id=${messageId}&evidence_type=${evType}`;

let messageText = `${t.title}\n━━━━━━━━━━━━━━━━━━━━\n\n`;
messageText += `${t.section_reason}\n<i>${reason}</i>\n\n`;

if (legalStatus && legalStatus !== "N/A" && legalStatus !== "null") {
    messageText += `${t.section_legal}\n<i>${legalStatus}</i>\n\n`;
}

if (strategy && strategy !== "null") {
    messageText += `${t.section_strategy}\n<b>${strategy}</b>\n\n`;
}

messageText += `━━━━━━━━━━━━━━━━━━━━\n⚠️ L'operazione è stata annullata. Carica un'evidenza valida per procedere.`;

const telegramApiPayload = {
  method: "editMessageText",
  chat_id: chatId,
  message_id: messageId,
  text: messageText,
  parse_mode: "HTML",
  reply_markup: {
    inline_keyboard: [
      [{ text: t.btn_retry, web_app: { url: webAppUrl } }],
      [{ text: t.btn_back, callback_data: `get_active_sop_SVC_${sopId.replace('SVC_', '')}` }]
    ]
  }
};

return [{ json: { ...item, telegramApiPayload: telegramApiPayload } }];

// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Evidence_Accepted_Message (AGNOSTICO & FIXED)
// DESC: Rendering dinamico di dati certificati con pulizia HTML
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;
const owner = item.owner_data || {};

// --- FUNZIONE DI PULIZIA TAG (Anti-Errore Telegram) ---
function clean(text) {
    if (!text || typeof text !== 'string') return "";
    // Rimuove tutti i tag <...> tranne quelli supportati da Telegram
    return text.replace(/<(?!b\b|i\b|u\b|s\b|code\b|a\b|pre\b|\/b\b|\/i\b|\/u\b|\/s\b|\/code\b|\/a\b|\/pre\b)[^>]+>/gi, '');
}

// 1. Identificativi
const chatId = item.body.chat_id || owner.chat_id;
const messageId = item.body.message_id; 
const sopId = item.body.sop_id;
const stepName = clean(item.current_step_context?.step_name || "OPERAZIONE");

// 2. Recupero Dati dall'AI
const log = item.Evicence_Rational_Log || {};
const extracted = log.extracted_value || {};
const legalStatus = clean(log.fiscal_legal_status || "");
const strategy = clean(log.strategic_insight || "");

// 3. Rilevamento Lingua
const rawLang = (owner.lenguage || 'it').toLowerCase();
let lang = rawLang.includes('en') ? 'en' : 'it';

const t = {
  it: {
    title: `✅ <b>CERTIFICATO: ${stepName.toUpperCase()}</b>`,
    section_data: "📊 <b>DATI RILEVATI:</b>",
    section_legal: "⚖️ <b>ANALISI NORMATIVA:</b>",
    section_strategy: "💡 <b>INTELLIGENCE:</b>",
    footer: "Il log è stato salvato nel Registro Aziendale SiteBoS.",
    btn_next: "⏭️ Prosegui"
  },
  en: {
    title: `✅ <b>CERTIFIED: ${stepName.toUpperCase()}</b>`,
    section_data: "📊 <b>DETECTED DATA:</b>",
    section_legal: "⚖️ <b>LEGAL ANALYSIS:</b>",
    section_strategy: "💡 <b>INTELLIGENCE:</b>",
    footer: "The log has been saved in the SiteBoS Audit Registry.",
    btn_next: "⏭️ Continue"
  }
}[lang];

// 4. DIZIONARIO EMOJI AGNOSTICO
const emojiMap = {
    temp: "🌡️", date: "📅", time: "🕒", amount: "💰", price: "💵", 
    vat: "📉", user: "👤", merchant: "🏪", address: "📍", status: "⚙️",
    id: "🆔", code: "🔢", mail: "📧", phone: "📞", check: "✔️"
};

// 5. FORMATTATORE UNIVERSALE DI CHIAVI
function formatKey(key) {
    const cleanKey = key.toLowerCase();
    let icon = "🔹";
    for (const [k, e] of Object.entries(emojiMap)) {
        if (cleanKey.includes(k)) {
            icon = e;
            break;
        }
    }
    const label = key.replace(/_/g, ' ').toUpperCase();
    return `${icon} ${label}`;
}

// 6. COSTRUZIONE DINAMICA RIGHE DATI
let dataRows = [];
if (typeof extracted === 'object' && extracted !== null) {
    for (const [key, value] of Object.entries(extracted)) {
        if (Array.isArray(value) || typeof value === 'object' || value === null || value === "") continue;
        // Puliamo anche il valore se è una stringa
        const cleanValue = typeof value === 'string' ? clean(value) : value;
        dataRows.push(`${formatKey(key)}: <b>${cleanValue}</b>`);
    }
} else if (typeof extracted === 'string' && extracted.length > 0) {
    dataRows.push(`📌 VALORE: <b>${clean(extracted)}</b>`);
}

// 7. COMPOSIZIONE MESSAGGIO
let messageText = `${t.title}\n━━━━━━━━━━━━━━━━━━━━\n\n`;

if (dataRows.length > 0) {
    messageText += `${t.section_data}\n${dataRows.join("\n")}\n\n`;
}

if (legalStatus && legalStatus !== "N/A" && legalStatus !== "null") {
    messageText += `${t.section_legal}\n<i>${legalStatus}</i>\n\n`;
}

if (strategy && strategy !== "null") {
    messageText += `${t.section_strategy}\n<i>${strategy}</i>\n\n`;
}

messageText += `━━━━━━━━━━━━━━━━━━━━\n${t.footer}`;

// 8. Payload per Telegram
const telegramApiPayload = {
  method: "editMessageText",
  chat_id: chatId,
  message_id: messageId,
  text: messageText,
  parse_mode: "HTML",
  reply_markup: {
    inline_keyboard: [
      [{ text: t.btn_next, callback_data: `get_active_sop_SVC_${sopId.replace('SVC_', '')}` }]
    ]
  }
};

return [{ json: { ...item, telegramApiPayload: telegramApiPayload } }];

// ═══════════════════════════════════════════════════════════════
// NODO: Final_Data_Consolidator
// DESC: Consolidamento metadati tecnici e intelligence AI
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;
const body = item.body || {};
const aiResult = item.Evicence_Rational_Log || {};

// 1. Costruzione del pacchetto di certificazione completo
const finalAuditLog = {
    // --- IDENTIFICAZIONE ---
    vat_number: body.vat,
    sop_id: body.sop_id,
    step_id: body.step_id,
    operator_id: body.chat_id,

    // --- TRACCIABILITÀ TEMPORALE ---
    timestamp_request: body.timestamp, // Quando l'utente ha scattato/inviato
    timestamp_certified: new Date().toISOString(), // Quando l'AI ha messo il timbro

    // --- NATURA DEL DATO ---
    evidence_type: body.evidence_type,

    // --- INTELLIGENCE & ESITO ---
    success: aiResult.success || false,
    rationale: aiResult.rationale || "Errore durante la generazione del razionale.",
    extracted_value: aiResult.extracted_value || null,
    fiscal_legal_status: aiResult.fiscal_legal_status || "N/A",
    strategic_insight: aiResult.strategic_insight || "N/A"
};

// 2. Pulizia: sostituiamo l'oggetto nel flusso con quello consolidato
return {
    json: {
        ...item,
        Final_Audit_Log: finalAuditLog
    }
};

// ═══════════════════════════════════════════════════════════════
// NODO: StepIsolator
// DESC: Estrae solo i dettagli dello step specifico dal Blueprint
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;

// 1. Recupero Blueprint e ID dello step dal webhook
const blueprint = item.Blueprint || {};
const targetStepId = item.body.step_id;

let currentStep = null;

// 2. Ricerca ricorsiva dello step nei vari stage
if (blueprint.stages && Array.isArray(blueprint.stages)) {
    for (const stage of blueprint.stages) {
        if (stage.steps && Array.isArray(stage.steps)) {
            const found = stage.steps.find(s => s.step_id === targetStepId);
            if (found) {
                currentStep = found;
                break; 
            }
        }
    }
}

// 3. Gestione errore (se lo step non esiste nel blueprint)
if (!currentStep) {
    return [{
        json: {
            ...item,
            error: "STEP_NOT_FOUND",
            error_details: `Lo step ${targetStepId} non è stato trovato nel blueprint ${item.body.sop_id}`
        }
    }];
}

// 4. Output pulito: passiamo solo lo step essenziale
return [{
    json: {
        ...item,
        current_step_details: {
            step_name: currentStep.step_name,
            instructions: currentStep.instructions,
            evidence_type: currentStep.quality_check.evidence_type,
            check_description: currentStep.quality_check.check_description,
            acceptance_criteria: currentStep.quality_check.acceptance_criteria
        }
    }
}];

